import openpyxl

# Read PWT data for Georgia
wb = openpyxl.load_workbook('/tmp/pwt100.xlsx', read_only=True)
print('PWT sheets:', wb.sheetnames)

# Check the data sheet
ws = wb['PWT_100']
# Find column headers
headers = {}
for cell in ws[1]:
    if cell.value:
        headers[cell.column] = cell.value

print('Columns:', {k: v for k, v in headers.items() if v in ['country', 'countrycode', 'year', 'rnna', 'rgdpna', 'rkna', 'cn', 'hc', 'pl_gdpo', 'pop']})

# Find Georgia's rnna data
georgia_data = {}
