import openpyxl

# Check all Georgia PWT data 2019-2023
wb = openpyxl.load_workbook('/tmp/pwt100.xlsx', read_only=True)
ws = wb['Data']
headers = {}
for cell in ws[1]:
    if cell.value:
        headers[cell.column] = cell.value

print('All columns:', {k: v for k, v in headers.items()})

for row in ws.iter_rows(min_row=2, values_only=False):
    vals = {}
    for cell in row:
        if cell.column in headers:
            vals[headers[cell.column]] = cell.value
    if vals.get('country') and 'Georgia' in str(vals.get('country','')):
